SELECT dataset_name, dataset_description, dataset_url
FROM exoplanet_datasets
WHERE exoplanet_id = 1;

SELECT exoplanet_id
FROM discovery_details
WHERE discovery_method = 'Transit';

SELECT name
FROM exoplanets
WHERE discovery_date = (
  SELECT MAX(discovery_date)
  FROM exoplanets
);

SELECT name
FROM exoplanets
WHERE surface_temperature = (SELECT MAX(surface_temperature) FROM exoplanets);

SELECT name
FROM exoplanets
ORDER BY name;

SELECT COUNT(exoplanet_id) AS total_exoplanets
FROM discovery_details
WHERE discovery_team = 'NASA Exoplanet Hunting Team' AND telescope_used = 'Kepler Space Telescope';

SELECT name
FROM exoplanets
ORDER BY name ASC;
